// Iteramos sobre todos los items
return items.map(item => {
  try {
    // 1. Obtenemos el string
    let rawContent = item.json.output || "";

    // 2. Limpieza de Markdown
    let cleanContent = rawContent
      .replace(/^```json\s*/i, '')
      .replace(/^```\s*/i, '')
      .replace(/\s*```$/, '')
      .trim();

    // -----------------------------------------------------------
    // 3. REPARACIÓN Y NORMALIZACIÓN (El Parche)
    // -----------------------------------------------------------

    // A. Reparar cierre incorrecto de propiedades (tu parche original)
    cleanContent = cleanContent.replace(/(\n\s*)"\s*,/g, '$1},');

    // B. Normalizar "null" -> null (Quitar comillas a los nulls)
    // Esta regex busca : seguido de opcionalmente espacios, "null" y luego una coma o fin de objeto
    cleanContent = cleanContent.replace(/:\s*"null"(\s*[,}])平衡/g, ': null$1');

    // Versión más agresiva si la anterior es muy específica:
    cleanContent = cleanContent.replace(/:\s*"null"/g, ': null');

    // -----------------------------------------------------------

    // 4. Parseo
    const parsedData = JSON.parse(cleanContent);

    // 5. Retorno Exitoso
    return {
      json: parsedData
    };

  } catch (error) {
    return {
      json: {
        error: true,
        message: "Error al parsear el JSON tras la limpieza.",
        original_error: error.message,
        cleaned_string: item.json.output // Enviamos el original para debug
      }
    };
  }
});

