const rawItems = $input.all().map(item => item.json);

/* =========================
   1) UTILIDADES
========================= */

function isReportObject(obj) {
  return !!(
    obj &&
    typeof obj === 'object' &&
    !Array.isArray(obj) &&
    typeof obj.resumen_ejecutivo === 'string' &&
    obj.secciones &&
    typeof obj.secciones === 'object'
  );
}

function extractPayload(value) {
  if (isReportObject(value)) return value;

  if (Array.isArray(value)) {
    for (const item of value) {
      const found = extractPayload(item);
      if (found) return found;
    }
    return null;
  }

  if (value && typeof value === 'object') {
    for (const key of Object.keys(value)) {
      const found = extractPayload(value[key]);
      if (found) return found;
    }
  }

  return null;
}

const data = extractPayload(rawItems);

if (!data) {
  throw new Error(
    'No encontré un objeto con la estructura esperada: { resumen_ejecutivo, secciones }.'
  );
}

function escapeHtml(value) {
  return String(value ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

function prettyLabel(key) {
  return String(key || '')
    .replace(/_/g, ' ')
    .replace(/\b\w/g, c => c.toUpperCase());
}

function isNumericLike(value) {
  return (
    typeof value === 'number' ||
    (typeof value === 'string' && value.trim() !== '' && !isNaN(value))
  );
}

function formatNumber(value, decimals = 2) {
  return Number(value).toLocaleString('es-MX', {
    minimumFractionDigits: 0,
    maximumFractionDigits: decimals,
  });
}

function formatDate(value, withTime = true) {
  if (!value) return '—';

  const d = new Date(value);
  if (Number.isNaN(d.getTime())) return escapeHtml(value);

  return new Intl.DateTimeFormat('es-MX', {
    year: 'numeric',
    month: '2-digit',
    day: '2-digit',
    ...(withTime
      ? {
          hour: '2-digit',
          minute: '2-digit',
          hour12: false,
        }
      : {}),
  }).format(d);
}

function formatMonthYear(value) {
  if (!value) return 'Periodo no definido';

  const d = new Date(value);
  if (Number.isNaN(d.getTime())) return escapeHtml(value);

  const month = new Intl.DateTimeFormat('es-MX', {
    month: 'long',
  }).format(d);

  const year = new Intl.DateTimeFormat('es-MX', {
    year: 'numeric',
  }).format(d);

  return `${month.charAt(0).toUpperCase() + month.slice(1)} ${year}`;
}

function secondsToHuman(seconds) {
  if (!isNumericLike(seconds)) return '—';

  const totalSec = Number(seconds);
  const totalMin = Math.round(totalSec / 60);

  if (totalMin < 60) return `${totalMin} min`;

  const h = Math.floor(totalMin / 60);
  const m = totalMin % 60;
  return m === 0 ? `${h} h` : `${h} h ${m} min`;
}

function formatValue(key, value) {
  if (value === null || value === undefined || value === '') return '—';

  const lowerKey = String(key).toLowerCase();

  if (lowerKey.includes('fecha') || lowerKey.includes('hora')) {
    return formatDate(value, true);
  }

  if (lowerKey.endsWith('_sec') || lowerKey.includes('duracion')) {
    return secondsToHuman(value);
  }

  if (lowerKey.endsWith('_pct') || lowerKey.includes('por_100') || lowerKey.includes('tasa')) {
    return `${formatNumber(value, 2)}%`;
  }

  if (lowerKey.includes('telefono') || lowerKey.includes('num_telefono')) {
    return escapeHtml(value);
  }

  if (typeof value === 'boolean') {
    return value ? 'Sí' : 'No';
  }

  if (isNumericLike(value)) {
    return formatNumber(value, 2);
  }

  return escapeHtml(value);
}

function renderParagraphs(text) {
  if (!text) return '<p class="muted">Sin resumen narrativo.</p>';

  return String(text)
    .split(/\n\s*\n/)
    .filter(Boolean)
    .map(p => `<p>${escapeHtml(p)}</p>`)
    .join('');
}

function renderTable(rows = []) {
  if (!Array.isArray(rows) || rows.length === 0) {
    return `<div class="empty-state">Sin datos detallados.</div>`;
  }

  const columns = Array.from(
    rows.reduce((acc, row) => {
      Object.keys(row || {}).forEach(k => acc.add(k));
      return acc;
    }, new Set())
  );

  const thead = `
    <thead>
      <tr>
        ${columns
          .map(col => `<th>${escapeHtml(prettyLabel(col))}</th>`)
          .join('')}
      </tr>
    </thead>
  `;

  const tbody = `
    <tbody>
      ${rows
        .map(row => {
          return `
            <tr>
              ${columns
                .map(col => `<td>${formatValue(col, row?.[col])}</td>`)
                .join('')}
            </tr>
          `;
        })
        .join('')}
    </tbody>
  `;

  return `
    <div class="table-wrap">
      <table>
        ${thead}
        ${tbody}
      </table>
    </div>
  `;
}

function renderMetricCards(kpiRow = {}) {
  const cards = [
    {
      label: 'Chats Totales',
      value: kpiRow.chats_totales != null ? formatNumber(kpiRow.chats_totales, 0) : '—',
      tone: '',
    },
    {
      label: 'Tasa de Resolución',
      value: kpiRow.tasa_resolucion_pct != null
        ? `${formatNumber(kpiRow.tasa_resolucion_pct, 2)}%`
        : '—',
      tone: '',
    },
    {
      label: 'Tasa de Escalado',
      value: kpiRow.tasa_escalado_pct != null
        ? `${formatNumber(kpiRow.tasa_escalado_pct, 2)}%`
        : '—',
      tone: 'warn',
    },
    {
      label: 'Calidad de Handoff',
      value: kpiRow.handoff_quality_promedio != null
        ? `${formatNumber(kpiRow.handoff_quality_promedio, 2)} / 3`
        : '—',
      tone: '',
    },
    {
      label: 'Pedidos (Deliv / TakeAway)',
      value: `${kpiRow.pedidos_delivery ?? 0} / ${kpiRow.pedidos_takeaway ?? 0}`,
      tone: '',
    },
    {
      label: 'Errores Detectados',
      value: kpiRow.tasa_error_pct != null
        ? `${formatNumber(kpiRow.tasa_error_pct, 2)}%`
        : '—',
      tone: 'warn',
    },
    {
      label: 'Riesgo Alto',
      value: kpiRow.tasa_riesgo_high_pct != null
        ? `${formatNumber(kpiRow.tasa_riesgo_high_pct, 2)}%`
        : '—',
      tone: 'danger',
    },
    {
      label: 'Mensajes por Chat (Prom)',
      value: kpiRow.mensajes_promedio != null
        ? formatNumber(kpiRow.mensajes_promedio, 2)
        : '—',
      tone: '',
    },
  ];

  return `
    <div class="metrics-grid">
      ${cards
        .map(card => {
          return `
            <div class="metric-card ${card.tone}">
              <div class="metric-label">${escapeHtml(card.label)}</div>
              <div class="metric-value">${escapeHtml(card.value)}</div>
            </div>
          `;
        })
        .join('')}
    </div>
  `;
}

function renderResolutionCard(kpiRow = {}) {
  const rate = kpiRow.tasa_resolucion_pct ?? '—';
  const total = kpiRow.chats_totales ?? '—';

  return `
    <div class="score-card">
      <div class="score-label">Tasa de Resolución</div>
      <div class="score-value">${escapeHtml(rate)}%</div>
      <div class="score-stars">★★★★★</div>
      <div class="score-foot">Chats: ${escapeHtml(total)}</div>
    </div>
  `;
}

function renderSection(sectionKey, section, index) {
  const sectionColors = {
    kpis_delivery: 'accent-black',
    riesgos_negocio: 'accent-red',
    intenciones: 'accent-black',
    horarios: 'accent-black',
    estado_emocional: 'accent-black',
    sentimiento_negativo: 'accent-red',
    temas_conversaciones: 'accent-black',
    escalaciones: 'accent-black',
  };

  const colorClass = sectionColors[sectionKey] || 'accent-black';
  let rows = Array.isArray(section?.datos_detallados) ? section.datos_detallados : [];

  if (sectionKey === 'escalaciones') {
    // Se retiran los campos "Tono Sentimiento", "Urgencia" y "Estado"
    rows = rows.map(row => {
      const newRow = { ...row };
      delete newRow.tono_sentimiento;
      delete newRow.urgencia;
      delete newRow.estado;
      return newRow;
    });
  }

  if (sectionKey === 'kpis_delivery') {
    const kpiRow = rows[0] || {};

    return `
      <section class="card ${colorClass}">
        <div class="section-title">
          <span class="section-index">${index}.</span>
          <span>${escapeHtml(section?.titulo || prettyLabel(sectionKey))}</span>
        </div>

        <div class="section-text">
          ${renderParagraphs(section?.resumen_narrativo)}
        </div>

        ${renderMetricCards(kpiRow)}

      </section>
    `;
  }

  if (sectionKey === 'temas_conversaciones') {
    return `
      <section class="card ${colorClass}">
        <div class="section-title">
          <span class="section-index">${index}.</span>
          <span>${escapeHtml(section?.titulo || prettyLabel(sectionKey))}</span>
        </div>

        <div class="section-text">
          ${renderParagraphs(section?.resumen_narrativo)}
        </div>

        <div class="subsection-title">Distribución de Temas de Mensajes</div>
        ${renderTable(rows)}
      </section>
    `;
  }

  return `
    <section class="card ${colorClass}">
      <div class="section-title">
        <span class="section-index">${index}.</span>
        <span>${escapeHtml(section?.titulo || prettyLabel(sectionKey))}</span>
      </div>

      <div class="section-text">
        ${renderParagraphs(section?.resumen_narrativo)}
      </div>

      ${renderTable(rows)}
    </section>
  `;
}

/* =========================
   2) DATOS DERIVADOS
========================= */

